export function getTopic(id) { return TOPICS.find((t) => t.id === Number(id)); }
export function readyTopics() { return TOPICS.filter((t) => t.status === 'ready'); }
export function allFlashcards() {
  return readyTopics().flatMap((t) => (t.flashcards || []).map((c, i) => ({ ...c, topicId: t.id, idx: i })));
}
export function allMcq() {
  return readyTopics().flatMap((t) => (t.mcq || []).map((q, i) => ({ ...q, topicId: t.id, idx: i })));
}
